#!/usr/bin/env python
# -*- coding: utf-8 -*-

import json
from ths_exception import notify_error, ExceptionType


def run_pine_script(param):
    # 模块入口：供c++、python等其他模块调用
    try:
        if isinstance(param, dict):
            data = param
        else:
            data = json.loads(param)
        if 'version' in data.keys():
            # 新版下单
            from . import neworder
            neworder.ScriptMgr.instance().on_event(data)
        else:
            # 统一版下单
            from . import oldorder
            oldorder.ScriptMgr.instance().on_event(data)
    except Exception:
        notify_error(ExceptionType.protocol, param)
